import{_ as a,o as s,c as r,a3 as i}from"./chunks/framework.DxStgKjp.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"clice/design/architecture.md","filePath":"en/clice/design/architecture.md"}'),o={name:"clice/design/architecture.md"};function c(n,e,t,l,d,p){return s(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>clice uses a <strong>multi-process</strong> architecture: a master server coordinates multiple worker processes. The master handles LSP requests, manages state, and dispatches compilation tasks. Workers perform CPU-intensive work (parsing, indexing) in separate processes with memory limits.</p><p>The async runtime is provided by <a href="https://github.com/clice-io/kotatsu" target="_blank" rel="noreferrer">kotatsu</a> (<code>kota</code>), which wraps libuv with C++20 coroutines. clice never calls libuv directly.</p><h2 id="source-modules" tabindex="-1">Source Modules <a class="header-anchor" href="#source-modules" aria-label="Permalink to &quot;Source Modules&quot;">​</a></h2><h3 id="src-command" tabindex="-1"><code>src/command/</code> <a class="header-anchor" href="#src-command" aria-label="Permalink to &quot;`src/command/`&quot;">​</a></h3><p>CLI parsing, compilation database loading, and toolchain detection. Implements the subcommand-based interface (<code>clice server</code>, <code>clice query</code>, etc.).</p><h3 id="src-compile" tabindex="-1"><code>src/compile/</code> <a class="header-anchor" href="#src-compile" aria-label="Permalink to &quot;`src/compile/`&quot;">​</a></h3><p>Compilation unit abstraction. Wraps Clang&#39;s AST and preprocessor state, providing:</p><ul><li><code>CompilationUnitRef</code> — unified access to source locations, directives, file content</li><li><code>DiagnosticID</code> — diagnostic classification (deprecated, unused, etc.)</li><li>Preprocessor directive tracking (includes, embeds, module declarations)</li></ul><h3 id="src-feature" tabindex="-1"><code>src/feature/</code> <a class="header-anchor" href="#src-feature" aria-label="Permalink to &quot;`src/feature/`&quot;">​</a></h3><p>LSP feature implementations, each consuming a <code>CompilationUnitRef</code>:</p><ul><li>Code completion, hover, signature help</li><li>Semantic tokens, inlay hints, document symbols</li><li>Document links, folding ranges, formatting, diagnostics</li></ul><h3 id="src-index" tabindex="-1"><code>src/index/</code> <a class="header-anchor" href="#src-index" aria-label="Permalink to &quot;`src/index/`&quot;">​</a></h3><p>Symbol indexing for cross-TU queries:</p><ul><li><code>TUIndex</code> — per-translation-unit symbol data</li><li><code>ProjectIndex</code> — global symbol index with workspace-wide queries</li><li><code>MergedIndex</code> — per-file shards merging header contexts</li><li>Include graph tracking</li></ul><p>Serialized with FlatBuffers for efficient disk storage.</p><h3 id="src-semantic" tabindex="-1"><code>src/semantic/</code> <a class="header-anchor" href="#src-semantic" aria-label="Permalink to &quot;`src/semantic/`&quot;">​</a></h3><p>Semantic analysis beyond what raw Clang provides:</p><ul><li><code>SemanticVisitor</code> — AST traversal recording symbol occurrences and relations</li><li><code>TemplateResolver</code> — pseudo-instantiation for dependent name resolution</li><li><code>find_target</code> — resolve nodes to their declaration targets</li><li>Symbol kind/modifier classification</li></ul><h3 id="src-syntax" tabindex="-1"><code>src/syntax/</code> <a class="header-anchor" href="#src-syntax" aria-label="Permalink to &quot;`src/syntax/`&quot;">​</a></h3><p>Lightweight syntax-level processing (no full AST needed):</p><ul><li><code>Lexer</code> (<code>lexer.h</code>) and directive scanning (<code>scan.h</code>, wraps Clang&#39;s <code>DependencyDirectivesScanner</code>) — token-level utilities</li><li><code>DependencyGraph</code> — module/include dependency tracking</li><li>Include path completion, module import completion</li></ul><h3 id="src-server" tabindex="-1"><code>src/server/</code> <a class="header-anchor" href="#src-server" aria-label="Permalink to &quot;`src/server/`&quot;">​</a></h3><p>The server core, split into sub-modules:</p><h4 id="src-server-service" tabindex="-1"><code>src/server/service/</code> <a class="header-anchor" href="#src-server-service" aria-label="Permalink to &quot;`src/server/service/`&quot;">​</a></h4><ul><li><code>MasterServer</code> — top-level LSP server, routes requests to sessions/workers</li><li><code>LSPClient</code> — LSP protocol handler, capability registration</li><li><code>Session</code> — per-file state (active context, pending requests)</li></ul><h4 id="src-server-compiler" tabindex="-1"><code>src/server/compiler/</code> <a class="header-anchor" href="#src-server-compiler" aria-label="Permalink to &quot;`src/server/compiler/`&quot;">​</a></h4><ul><li><code>Compiler</code> — compilation orchestration (PCH, PCM, index builds)</li><li><code>CompileGraph</code> — interest-counted module DAG with cancellation</li><li><code>Indexer</code> — background indexing, query resolution</li></ul><h4 id="src-server-worker" tabindex="-1"><code>src/server/worker/</code> <a class="header-anchor" href="#src-server-worker" aria-label="Permalink to &quot;`src/server/worker/`&quot;">​</a></h4><ul><li><code>StatefulWorker</code> — holds ASTs in memory, serves queries (hover, semantic tokens, etc.)</li><li><code>StatelessWorker</code> — ephemeral tasks (PCH/PCM builds, completion, signature help)</li><li><code>WorkerPool</code> — process lifecycle management</li></ul><h4 id="src-server-workspace" tabindex="-1"><code>src/server/workspace/</code> <a class="header-anchor" href="#src-server-workspace" aria-label="Permalink to &quot;`src/server/workspace/`&quot;">​</a></h4><ul><li><code>Workspace</code> — project state, config, dependency graph</li><li><code>Config</code> — TOML/JSON config loading and validation</li></ul><h3 id="src-support" tabindex="-1"><code>src/support/</code> <a class="header-anchor" href="#src-support" aria-label="Permalink to &quot;`src/support/`&quot;">​</a></h3><p>Utilities: logging, filesystem helpers, JSON serialization, string operations.</p><h2 id="process-model" tabindex="-1">Process Model <a class="header-anchor" href="#process-model" aria-label="Permalink to &quot;Process Model&quot;">​</a></h2><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────┐</span></span>\n<span class="line"><span>│                  Master Process                   │</span></span>\n<span class="line"><span>│  event loop (kota) + LSP I/O + state management │</span></span>\n<span class="line"><span>└────────────┬──────────────────┬─────────────────┘</span></span>\n<span class="line"><span>             │ bincode IPC      │ bincode IPC</span></span>\n<span class="line"><span>     ┌───────▼───────┐   ┌─────▼──────────┐</span></span>\n<span class="line"><span>     │ Stateful       │   │ Stateless       │</span></span>\n<span class="line"><span>     │ Workers (×2)   │   │ Workers (×N/2)  │</span></span>\n<span class="line"><span>     │ hold ASTs,     │   │ build PCH/PCM,  │</span></span>\n<span class="line"><span>     │ serve queries  │   │ completion,     │</span></span>\n<span class="line"><span>     └───────────────┘   │ signature help  │</span></span>\n<span class="line"><span>                          └─────────────────┘</span></span></code></pre></div><p>Workers communicate with the master via stdin/stdout using bincode serialization. Each worker runs in its own process with a configurable memory limit (default 4 GB).</p>',37)])])}const m=a(o,[["render",c]]);export{h as __pageData,m as default};
